class Solution {
public:
    long long minSumSquareDiff(vector<int>& nums1, vector<int>& nums2, int k1, int k2) {
        long long res = 0;
        priority_queue<pair<long long, int>> pq;
        int k = k1 + k2;
        for (int i = 0; i < nums1.size(); i++) {
            long long diff = abs(nums1[i] - nums2[i]);
            res += diff * diff;
            pq.push({diff, i});
        }
        while (k-- > 0 && !pq.empty()) {
            auto [diff, i] = pq.top(); pq.pop();
            long long newDiff = max(diff - 1, 0LL);
            res -= diff * diff;
            res += newDiff * newDiff;
            pq.push({newDiff, i});
        }
        return res;
    }
};
```
